#define THREADS 256

__kernel void c_CopySrcToComponents(__global float *d_r, __global float *d_g, __global float *d_b, 
                                    __global uchar *d_src, int pixels)
{
    int x = get_local_id(0);
    int gX = get_group_id(0) * get_local_size(0);

    __local uchar sData[THREADS*3];

    int idx = x * 3;
    if (idx + 2 < THREADS * 3) {
        sData[idx] = d_src[(gX * 3) + idx];
        sData[idx + 1] = d_src[(gX * 3) + idx + 1];
        sData[idx + 2] = d_src[(gX * 3) + idx + 2];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float r = (float)(sData[idx]);
    float g = (float)(sData[idx + 1]);
    float b = (float)(sData[idx + 2]);

    int globalOutputPosition = gX + x;
    if (pixels > globalOutputPosition) {
        d_r[globalOutputPosition] = (r / 255.0f) - 0.5f;
        d_g[globalOutputPosition] = (g / 255.0f) - 0.5f;
        d_b[globalOutputPosition] = (b / 255.0f) - 0.5f;
    }
}

